mapper.select:
/* OutboundOrderReceiveMapper.xml - selectOrdSepStgCd - 주문분리 전략조회 */
SELECT
	ORDSEPSTGCD AS ORDSEPTEMPCD
	,'KOR' AS SLAKEY
FROM TWORK_INFO_ORD_SEP_STG_MSTR
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND USEYN = 'Y'

mapper.insert:
/* OutboundOrderReceiveMapper.xml - insertOutboundOrderDetail - 출고 주문 정보 상세 등록 */
INSERT INTO TWORK_INFO_OB_ORD_DT
(
	CTKEY
	, OWKEY
	, OBORDKEY
	, OBORDDTKEY
	, ICKEY
	, ICUNITKEY
	, UOM
	, INITQTY
	, EXPCTQTY
	, CNFRMQTY
	, OBCNFRMDATE
	, OBCONFIRMURKEY
	, ORHDKEY
	, ORDTKEY
	, EXTERNORDERKEY
	, EXTERNORDERLINENUM
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
)
VALUES
(
	#{ctkey}
	,#{owkey}
	,#{obordkey}
	,#{ordtkey}
	,#{ickey}
	,#{icunitkey}
	,#{uom}
	,#{initqty}
	,#{expctqty}
	,0
	,NULL
	,NULL
	,#{orhdkey}
	,#{ordtkey}
	,#{externorderkey}
	,#{externorderlinenum}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
)

/* OutboundOrderReceiveMapper.xml - insertOutboundOrderHeader - 출고 주문 정보 헤더 등록 */
INSERT INTO TWORK_INFO_OB_ORD_HD
(
	CTKEY
	, OWKEY
	, OBORDKEY
	, OBHDTYPECD
	, OBHDDAY
	, OBREQDATE
	, OBCNFRMDATE
	, DLVYTYPECD
	, DLVYFORMCD
	, NISCNLRNGCD
	, ORDNM
	, RCPPRSNNM
	, RCPPRSNTELNO
	, RCPPRSNTELNO2
	, RCPPRSNZIPCD
	, RCPPRSNADDR1
	, RCPPRSNADDR2
	, DLVYMSG
	, CHNLID
	, ACKEY
	, ACNM
	, CNTRYCD
	, STATE
	, CTY
	, DLVRYCORPCD
	, TOCTKEY
	, STOREKEY
	, IBHDKEY
	, ORHDKEY
	, EXTERNORDERKEY
	, CLAIMNO
	, CNLRSNCD
	, CNLRSN
	, CMT
	, PRINFORCVPRGRYN
	, MALPRGRSTATUSCD
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
)
VALUES
(
	#{ctkey}
	,#{owkey}
	,#{obordkey}
	,#{obhdtypecd}
	,#{obhdday}
	,#{obreqdate}
	, NULL
	,#{dlvytypecd}
	,#{dlvyformcd}
	,#{niscnlrngcd}
	,#{ordprsnnm}
	,#{rcpprsnnm}
	,#{rcpprsntelno}
	,#{rcpprsntelno2}
	,#{rcpprsnzipcd}
	,#{rcpprsnaddr1}
	,#{rcpprsnaddr2}
	,#{dlvymsg}
	,#{chnlid}
	, NULL
	, NULL
	, NULL
	, NULL
	, NULL
	, NULL
	,#{toctkey}
	,#{storekey}
	, NULL
	,#{orhdkey}
	,#{externorderkey}
	,#{claimno}
	,#{cnlrsncd}
	,#{cnlrsn}
	,#{cmt}
	,'N'
	,'01'
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
)

mapper.update:
/* OutboundOrderReceiveMapper.xml - updateObHdCnl - 주문헤더 취소 업데이트 */
UPDATE TWORK_INFO_OB_HD
   SET OBSTATUSCD = '99'
	 , CNLRSNCD = #{cnlrsncd}
     , CNLRSN = #{cnlrsn}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = 'INTERFACE'
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND ORHDKEY = #{orhdkey}

   AND EXTERNORDERKEY = #{externorderkey}

mapper.insert:
/* OutboundOrderReceiveMapper.xml - updateObDtCnl - 주문상세 취소 업데이트 */
UPDATE TWORK_INFO_OB_DT
   SET OBDTSTATUSCD = '99'
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = 'INTERFACE'
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND ORHDKEY = #{orhdkey}

   AND EXTERNORDERKEY = #{externorderkey}

mapper.update:
/* OutboundOrderReceiveMapper.xml - updateInterfaceOutboundHeaderReceivePrcs - 출고 헤더 수신 인터페이스 처리결과 UPDATE */
UPDATE TWORK_INTF_OB_HD_RCV
SET PRCSYN = #{prcsyn}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = 'INTERFACE'
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND SOHDKEY IN

	#{item.orhdkey}

/* OutboundOrderReceiveMapper.xml - updateInterfaceOutboundDetailReceivePrcs - 출고 상세 수신 인터페이스 처리결과 UPDATE */
UPDATE TWORK_INTF_OB_DT_RCV
SET PRCSYN = #{prcsyn}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = 'INTERFACE'
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND SOHDKEY IN

	#{item.orhdkey}

/* OutboundOrderReceiveMapper.xml - updateInterfaceOutboundHeaderReceive - 출고 헤더 수신 인터페이스 처리결과 UPDATE */
UPDATE TWORK_INTF_OB_HD_RCV
SET PRCSYN = #{prcsyn}
	,PRCSDATE = #{sysdate}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND SOHDKEY = #{orhdkey}

/* OutboundOrderReceiveMapper.xml - updateInterfaceOutboundDetailReceive - 출고 상세 수신 인터페이스 처리결과 UPDATE */
UPDATE TWORK_INTF_OB_DT_RCV
SET PRCSYN = #{prcsyn}
	,PRCSDATE = #{sysdate}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND SOHDKEY = #{orhdkey}

/* OutboundOrderReceiveMapper.xml - callSpObDtInsert - 릴리즈 주문 상세 생성 */
{
	CALL SP_OB_DT_INSERT(
		#{ctkey,mode=IN,jdbcType=VARCHAR}
		, #{owkey,mode=IN,jdbcType=VARCHAR}
		, #{obhdkey,mode=IN,jdbcType=VARCHAR}
		, #{ickey,mode=IN,jdbcType=VARCHAR}
		, #{obdtstatuscd,mode=IN,jdbcType=VARCHAR}
		, #{icunitkey,mode=IN,jdbcType=VARCHAR}
		, #{uom,mode=IN,jdbcType=VARCHAR}
		, #{initqty,mode=IN,jdbcType=NUMERIC}
		, #{expctqty,mode=IN,jdbcType=NUMERIC}
		, #{alqty,mode=IN,jdbcType=NUMERIC} /*할당수량*/
		, #{pkistqty,mode=IN,jdbcType=NUMERIC} /*피킹지시수량*/
		, #{pkqty,mode=IN,jdbcType=NUMERIC} /*피킹수량*/
		, #{classifsqty,mode=IN,jdbcType=NUMERIC} /*분류수량*/
		, #{pakqty,mode=IN,jdbcType=NUMERIC} /*패킹수량*/
		, #{cnfrmqty,mode=IN,jdbcType=NUMERIC} /*확정수량*/
		, NULL /*출고확정일시*/
		, NULL /*출고확정자*/
		, #{obordkey,mode=IN,jdbcType=VARCHAR}
		, #{oborddtkey,mode=IN,jdbcType=VARCHAR}
		, #{orhdkey,mode=IN,jdbcType=VARCHAR}
		, #{ordtkey,mode=IN,jdbcType=VARCHAR}
		, #{externorderkey,mode=IN,jdbcType=VARCHAR}
		, #{externorderlinenum,mode=IN,jdbcType=VARCHAR}
		, #{sysdate,mode=IN,jdbcType=VARCHAR}
		, #{surkey,mode=IN,jdbcType=VARCHAR}
		, #{sysdate,mode=IN,jdbcType=VARCHAR}
		, #{surkey,mode=IN,jdbcType=VARCHAR}
		, #{O_CODE,mode=OUT,jdbcType=VARCHAR}
		, #{O_ERRM,mode=OUT,jdbcType=VARCHAR}
	)
}

/* OutboundOrderReceiveMapper.xml - callSpObSep - 자동분리 호출 */
{
	CALL SP_OB_SEP(
		#{ctkey,mode=IN,jdbcType=VARCHAR}
		, #{owkey,mode=IN,jdbcType=VARCHAR}
		, #{obhdkey,mode=IN,jdbcType=VARCHAR}
		, #{ordseptempcd,mode=IN,jdbcType=VARCHAR}
		, #{surkey,mode=IN,jdbcType=VARCHAR}
		, #{slakey,mode=IN,jdbcType=VARCHAR}
		, #{O_CODE,mode=OUT,jdbcType=VARCHAR}
		, #{O_ERRM,mode=OUT,jdbcType=VARCHAR}
	)
}
